def dfs_recursive(graph, start_node):
    visited = set()
    path = []

    def _dfs(node):
        if node not in visited:
            visited.add(node)
            path.append(node)
            for neighbor in graph.get(node, []):
                _dfs(neighbor)

    _dfs(start_node)
    return path


def dfs_iterative(graph, start_node):
    visited = set()
    stack = [start_node]
    path = []

    while stack:
        node = stack.pop()
        if node not in visited:
            visited.add(node)
            path.append(node)
            for neighbor in reversed(graph.get(node, [])):
                stack.append(neighbor)
    return path
